// Trim heavy fields, cap at 100 errors
const BYTE_LIMIT = 90000;
const MAX_ERRORS = 100;

const data = $input.first().json;
let errors = Array.isArray(data) ? data : (data.data || []);

// Cap count
const total = errors.length;
errors = errors.slice(0, MAX_ERRORS);

// Strip heavy fields per error record
const KEEP = new Set(['_id', 'code', 'message', 'source', 'classification', 
  'traceKey', 'retryDataKey', 'occurredAt', 'resolved', '_flowJobId']);
const trimmed = errors.map(e => {
  const out = {};
  for (const [k, v] of Object.entries(e)) {
    if (KEEP.has(k)) out[k] = v;
  }
  return out;
});

const result = {
  errors: trimmed,
  total_fetched: total,
  shown: trimmed.length,
  truncated: total > MAX_ERRORS,
};

// Safety byte check
const json = JSON.stringify(result);
if (json.length > BYTE_LIMIT) {
  result.errors = trimmed.slice(0, 10);
  result.shown = result.errors.length;
  result.truncated = true;
  result.hint = 'Response very large — showing first 10 errors only. Retry with a more specific step_id.';
}

return [{ json: result }];
